module RefModule (
    input wire clk,
    input wire signal_in,
    output reg zero_cross
);
    reg unused_signal_prev;

    always @(posedge clk) begin
        zero_cross <= (signal_in ^ unused_signal_prev) && unused_signal_prev != signal_in;
        unused_signal_prev <= signal_in;
    end
endmodule
